import { watchEmail, llmClassify, sendPushNotification, sendEmail, writeToDatabase } from './utils';

const newsletters: any[] = [];
const senderCounts: Record<string, number> = {};

async function main() {
  for await (const email of watchEmail({ filter: 'is:unread' })) {
    const category = await llmClassify(email.body, ['urgent', 'newsletter', 'other']);
    if (category === 'urgent') {
      await sendPushNotification(`Priority: ${email.subject}`);
    } else if (category === 'newsletter') {
      newsletters.push(email);
    } else {
      senderCounts[email.from] = (senderCounts[email.from] || 0) + 1;
    }
  }
}

async function sendWeeklyDigest() {
  await sendEmail('me@example.com', 'Weekly Digest', newsletters.map(n => n.subject).join('\n'));
  newsletters.length = 0;
}

import { fetchFromApi, sendEmail } from './utils';

async function generatePreVisitSummary(patientId: string) {
  const [labs, meds, vitals] = await Promise.all([
    fetchFromApi(`https://lims.hospital.org/api/results?patient=${patientId}`),
    fetchFromApi(`https://pharmacy.hospital.org/api/active-meds?patient=${patientId}`),
    fetchFromApi(`https://nursing.hospital.org/api/vitals?patient=${patientId}`),
  ]);
  const summary = { labResults: labs, activeMedications: meds, recentVitals: vitals, generatedAt: new Date().toISOString() };
  await sendEmail('physician@hospital.org', 'Pre-Visit Summary', JSON.stringify(summary));
}

import { fetchFromApi, logToAudit } from './utils';

let cachedPrice: number | null = null;

async function fetchPriceWithRetry(): Promise<number> {
  const maxRetries = 3;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      await logToAudit({ event: 'price_fetch_attempt', attempt });
      const result = await fetchFromApi('https://pricing.example.com/api/current');
      cachedPrice = result.price;
      await logToAudit({ event: 'price_fetch_success', attempt, price: result.price });
      return result.price;
    } catch (err) {
      await logToAudit({ event: 'price_fetch_failed', attempt, error: String(err) });
      if (attempt < maxRetries) {
        await new Promise(r => setTimeout(r, Math.pow(2, attempt) * 1000));
      }
    }
  }
  await logToAudit({ event: 'price_fetch_exhausted', fallback: cachedPrice });
  if (cachedPrice !== null) return cachedPrice;
  throw new Error('No cached price available');
}
